import{_ as l,C as t,o as i,c as o,ae as r,E as n}from"./chunks/framework.BzQXgbNp.js";const f=JSON.parse('{"title":"家庭小酒馆","description":"","frontmatter":{"title":"家庭小酒馆","date":"2025-08-20T02:01:23.000Z","draft":false},"headers":[],"relativePath":"posts/xiaojiuguan.md","filePath":"posts/xiaojiuguan.md","lastUpdated":1783569911000}'),s={name:"posts/xiaojiuguan.md"};function p(d,a,h,m,u,c){const e=t("ImageGallery");return i(),o("div",null,[a[0]||(a[0]=r('<h3 id="基酒" tabindex="-1">基酒 <a class="header-anchor" href="#基酒" aria-label="Permalink to &quot;基酒&quot;">​</a></h3><p>基酒是调酒的核心酒精部分，有白兰地、威士忌、朗姆酒、伏特加、金酒、龙舌兰</p><h3 id="利口酒" tabindex="-1">利口酒 <a class="header-anchor" href="#利口酒" aria-label="Permalink to &quot;利口酒&quot;">​</a></h3><p>利口酒用于调味与点缀，如君度橙酒、波士蓝橙等</p><h3 id="辅料" tabindex="-1">辅料 <a class="header-anchor" href="#辅料" aria-label="Permalink to &quot;辅料&quot;">​</a></h3><p>红石榴糖浆、甘蔗糖浆、薄荷叶、青柠、可乐、橙汁、气泡水、汤力水</p><h3 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h3><p>调酒：雪克壶、盎司杯、搅拌勺、榨汁器、捣棒</p><p>制冰：冰球、冰块、袋子</p><p>酒杯：柯林杯、玛格丽特杯等</p><h3 id="经典鸡尾酒" tabindex="-1">经典鸡尾酒 <a class="header-anchor" href="#经典鸡尾酒" aria-label="Permalink to &quot;经典鸡尾酒&quot;">​</a></h3><ul><li><p>玛格丽特：（龙舌兰 45ml、君度 30ml、柠檬汁 15ml、2块冰）shake，杯口沾盐 + 杯口插柠檬片</p></li><li><p>自由古巴：满冰，朗姆酒 45ml、柠檬汁 15ml（可选），杯中插入青柠片、可乐补满，提拉一下</p></li><li><p>龙舌兰日出：满冰，（龙舌兰 45ml、橙汁 120ml、柠檬汁 15ml、2块冰）shake，红石榴糖浆10ml，提拉 + 柠檬片 + 薄荷叶</p></li><li><p>莫吉托：（青柠切小块 + 薄荷叶）放杯内捣一捣，糖浆 20ml，朗姆酒 50ml，满冰，气泡水加满，顶部柠檬块 + 薄荷叶装饰</p></li><li><p>金汤力：满冰，金酒 50ml，柠檬汁 15ml，杯中插入柠檬、汤力水加满、提拉一下</p></li></ul><h3 id="注意" tabindex="-1">注意 <a class="header-anchor" href="#注意" aria-label="Permalink to &quot;注意&quot;">​</a></h3><ul><li>雪克壶在摇之前先开盖，避免壶内气压过大而炸壶</li></ul>',14)),n(e,{dir:"/images/xiaojiuguan/"})])}const x=l(s,[["render",p]]);export{f as __pageData,x as default};
